effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {

    vec2 adjOffs = offs / 1000.0;
    adjOffs.x *= acLayerSize.x/acLayerSize.y * -1.0;
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    float luminance = dot(texColor.rgb, luminanceWeighting);
    float px;
    float py;

    if( typex==0 ) {
        px = luminance;
    } else if( typex == 1 ) {
        px = texColor.r;
    } else if( typex == 2 ) {
        px= texColor.g;
    } else if( typex == 3 ) {
        px = texColor.b;
    } else {
        adjOffs *= 0.0;
    }

    if( typey==0 ) {
        py = luminance;
    } else if( typey == 1 ) {
        py = texColor.r;
    } else if( typey == 2 ) {
        py= texColor.g;
    } else if( typey == 3 ) {
        py = texColor.b;
    } else {
        adjOffs *= 0.0;
    }

    if( fromctr ) {
        px = (px-0.5)*2.0;
        py = (py-0.5)*2.0;
    }
    if( invert ) {
        px = 1.0-px;
        py = 1.0-py;
    }

    vec2 p = vec2(px,py);

    adjOffs *= p * texColor.a;

    vec2 sample = acScreenNorm + adjOffs;
    if(edges==0) {
        gl_FragColor = texture2DCv(comp.texture,sample);
    } else if(edges==1) {
        sample = vec2(1.0,1.0) - abs(mod(sample,vec2(2.0,2.0))-vec2(1.0,1.0));
        gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
    } else if(edges==2) {
        if( sample.x < 0.0 || sample.x > 1.0 || sample.y < 0.0 || sample.y > 1.0 ) {
            gl_FragColor = vec4(0.0,0.0,0.0,0.0);
        } else {
            gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
        }
    } else if(edges==3) {
        sample = mod(sample,vec2(1.0,1.0));
        gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
    } else {
        gl_FragColor = texture2DCv(comp.texture,sample) * texColor.a;
    }

}
